export const meta = {
  name: 'validate-min-slice',
  description: 'Validate domain schema + pure logic support the 4-behavior minimum TDD slice, then map done vs to-create',
  phases: [
    { title: 'Validate', detail: 'parallel readers over each layer vs the 4 behaviors' },
    { title: 'Trace', detail: 'adversarially trace the explanation data path end-to-end' },
  ],
}

const ROOT = '/Users/raunaksingh/Documents/realfast/insurance'

const BEHAVIORS = `
The MINIMUM TDD slice has exactly 4 target behaviors (happy path, full_coverage only):
  B1: POST /claims with 1 valid line  -> claim is persisted AND adjudicated
  B2: a full_coverage coverage rule   -> line outcome APPROVED, payable = full charge, member responsibility = 0
  B3: GET /claims/:id                  -> returns claim status + payable (READ path)
  B4: GET /claims/:id/explanation      -> returns reason code(s) + the numbers per line (READ path)
`

const READER_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['layer', 'behaviorSupport', 'gaps', 'correctnessRisks'],
  properties: {
    layer: { type: 'string' },
    behaviorSupport: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['behavior', 'status', 'evidence'],
        properties: {
          behavior: { type: 'string', enum: ['B1', 'B2', 'B3', 'B4', 'N/A'] },
          status: { type: 'string', enum: ['ready', 'partial', 'missing'] },
          evidence: { type: 'string', description: 'file:line + short quoted snippet proving the status' },
        },
      },
    },
    gaps: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['item', 'file', 'what', 'forBehavior'],
        properties: {
          item: { type: 'string' },
          file: { type: 'string', description: 'path to create or edit' },
          what: { type: 'string' },
          forBehavior: { type: 'string' },
        },
      },
    },
    correctnessRisks: {
      type: 'array',
      items: { type: 'string', description: 'anything in this layer that looks wrong/insufficient for the 4 behaviors' },
    },
  },
}

phase('Validate')

const readers = [
  {
    label: 'schema',
    prompt: `Read the persistence + entity schema in ${ROOT}: app/src/db/schema.ts, app/src/db/schema.sql, app/src/db/connection.ts, and everything under app/src/domain/entities/ and app/src/domain/money/.
${BEHAVIORS}
Validate ONLY whether the SCHEMA + ENTITY TYPES can support these 4 behaviors. In particular:
- Does the claims table store a fetchable status + a payable total for B3?
- Does the adjudications table (and its entity type) store BOTH the reason code(s) AND the per-line numbers (payable, deductible applied, copay, coinsurance, member responsibility) that B4 needs to return?
- Are line items + adjudications keyed so a GET-by-claim-id read is possible?
Quote exact column/field names with file:line. Report any missing column/field needed for B3 or B4 as a gap.`,
  },
  {
    label: 'adjudicate-line',
    prompt: `Read the pure adjudication logic in ${ROOT}: everything under app/src/domain/adjudication/ and app/src/domain/rules/.
${BEHAVIORS}
Validate ONLY the pure function path for B2 (full_coverage -> APPROVED). Confirm by quoting code:
- For a full_coverage rule, what outcome status does adjudicateLine return, and is payable = full charge with member responsibility = 0?
- Does the function's RETURN VALUE carry the reason code(s) AND the numbers (payable, member responsibility, deductible/copay/coinsurance breakdown) that B4's explanation endpoint will need? Or does it only return status + deltas, dropping the explanation numbers?
This is the riskiest area — be precise about exactly which fields the return type exposes. Quote the return type / object shape with file:line.`,
  },
  {
    label: 'aggregate+state',
    prompt: `Read ${ROOT}: everything under app/src/domain/state-machines/ and any aggregateClaimStatus logic (search app/src/domain for it).
${BEHAVIORS}
Validate ONLY: for a claim with exactly 1 line whose outcome is APPROVED, does aggregateClaimStatus return claim status APPROVED (B1+B2 rollup)? Are the state-machine transitions SUBMITTED->...->APPROVED valid for this happy path? Quote the relevant code with file:line.`,
  },
  {
    label: 'repos+service+http',
    prompt: `Read ${ROOT}: everything under app/src/repositories/, app/src/services/claim.service.ts, app/src/routes/, app/src/controllers/, app/src/app.ts, app/src/index.ts, app/src/db/seed.ts, and app/tests/db-helpers.ts.
${BEHAVIORS}
Validate the WIRING + READ paths:
- B1 write path: does claimService.adjudicateClaim already persist claim+lines+adjudications? Quote it.
- B3 read path: is there a repository method to FETCH a claim by id with its status + payable? If not, that's a gap.
- B4 read path: is there a repository method to FETCH adjudications (reasons + numbers) by claim id? The adjudication repo may only have append() — confirm whether a read method exists.
- HTTP layer: are routes/claims.routes.ts, controllers/claim.controller.ts, app.ts wired, or empty stubs? Confirm line counts / contents.
- seed.ts: real or empty?
List every missing piece as a precise gap (file to create/edit + what), each tagged to B1/B2/B3/B4.`,
  },
]

const findings = (await parallel(
  readers.map((r) => () =>
    agent(r.prompt, { label: `read:${r.label}`, phase: 'Validate', agentType: 'Explore', schema: READER_SCHEMA })
  )
)).filter(Boolean)

phase('Trace')

const TRACE_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['explanationDataPathIntact', 'breakPoint', 'reasoning', 'requiredFixes'],
  properties: {
    explanationDataPathIntact: { type: 'boolean', description: 'true if reason codes + numbers survive from pure logic -> adjudication row -> read -> GET /explanation' },
    breakPoint: { type: 'string', description: 'the FIRST place the explanation reasons/numbers are dropped or unavailable, or "none"' },
    reasoning: { type: 'string' },
    requiredFixes: { type: 'array', items: { type: 'string' } },
  },
}

const trace = await agent(
  `In ${ROOT}, adversarially TRACE the data needed by GET /claims/:id/explanation (B4: per-line reason code(s) + the numbers) end to end, and try to prove it BREAKS somewhere:
  1) Does the pure adjudicateLine return value carry reasons + numbers? (read app/src/domain/adjudication/)
  2) Does claimService.adjudicateClaim pass ALL of those into the adjudication row it persists? (read app/src/services/claim.service.ts + app/src/repositories/adjudication.repository.ts + the adjudications schema)
  3) Is there any READ method to get them back out for a GET endpoint?
  Default to explanationDataPathIntact=false unless you can quote code proving reasons AND numbers survive every hop. Name the FIRST break point precisely.
  Here are the layer findings to cross-check against:
  ${JSON.stringify(findings).slice(0, 6000)}`,
  { label: 'trace:explanation', phase: 'Trace', agentType: 'Explore', schema: TRACE_SCHEMA }
)

return { findings, trace }

