        ]
      },
      {
        "layer": "Pure Adjudication Logic (app/src/domain/adjudication/adjudicator.ts + repositories)",
        "behaviorSupport": [
          {
            "behavior": "B2",
            "status": "ready",
            "evidence": "app/src/domain/adjudication/adjudicator.ts:122-131 — full_coverage rule returns status='APPROVED', payableCents=line.billedCents, memberResponsibilityCents=0, reasons=['APPROVED'], explanation with formatted USD amounts"
