          }
        ],
        "gaps": [
          {
            "item": "POST /claims HTTP endpoint",
            "file": "app/src/routes/claims.routes.ts",
            "what": "Router stub; needs to bind claim.service.adjudicateClaim() and return {claimId, status}",
            "forBehavior": "B1"
          },
          {
            "item": "GET /claims/:id HTTP endpoint",
            "file": "app/src/routes/claims.routes.ts",
            "what": "Router stub; needs to query adjudication repository currentOutcomesByClaim() and return claim status + per-line {status, reasons}",
            "forBehavior": "B3"
          },
