            "item": "GET /claims/:id/explanation HTTP endpoint",
            "file": "app/src/routes/claims.routes.ts",
            "what": "Router stub; needs to query adjudication table for each line and return {lineId, reasons[], explanation, payableCents, memberResponsibilityCents}",
            "forBehavior": "B4"
