          },
          {
            "behavior": "B3",
            "status": "missing",
            "evidence": "GET /claims/:id endpoint stub only (claims.routes.ts:1-2 is header comment). No implementation reads claim status + aggregated payable. Must implement GET handler that sums line payables and returns claim status."
          },
          {
            "behavior": "B4",
            "status": "missing",
